<template>
  <div class="pay_wrap">
    <van-nav-bar
      title="微信支付"
      left-text="返回"
      left-arrow
      @click-left="$router.go(-1)"
    />
    <div class="qrcode bg-fff flex fdc aic jc-c">
      <img :src="params.qrCode" alt="" />
      <p>¥{{ params.totalMoney }}</p>
    </div>
    <van-cell-group>
      <van-cell title="收款方" value="天堂电子有限公司"></van-cell>
      <van-cell title="剩余时间">
        <van-count-down :time="time"></van-count-down>
      </van-cell>
    </van-cell-group>
  </div>
</template>

<script>
import $axios from "@/utils/index";
export default {
  data() {
    return {
      params: this.$route.query,
      timer: null,
    };
  },
  computed: {
    time() {
      

      return 15*60*1000-(Date.now()-this.params.createTime)
    },
  },
  created() {
    // console.log(this.$route.query);
    this.getOrderDetial()
  },
  destroyed(){
    clearInterval(this.timer)
  },
  methods: {
    // 轮询订单详情接口,查看订单状态
    getOrderDetial() {
      this.timer = setInterval(async () => {
        let res = await $axios.post("order/detail", {
          orderId: this.params.orderId,
        });
        let {orderStatus}=res.result
        // console.log(orderStatus)
        if(orderStatus==='01'){
          // console.log('跳转到订单列表')
          clearInterval(this.timer)
        }
      }, 2000);
    },
  },
};
</script>

